    cin.tie(0);
#define endl '\n'
#define f first
#define s second

typedef unsigned long long llu;
typedef unsigned int ui;
typedef long long ll;

int main()
{
    //_
    int n, i, c = 0, nc = 0;
    string nome;
    char sinal;
    cin >> n;

    vector<string> criancas;
    criancas.reserve(n);

    for (i = 0; i < n; i++)
    {
        cin >> sinal >> nome;
        if (sinal == '+')
            c++;
        else
            nc++;
        criancas.push_back(nome);
    }

    sort(criancas.begin(),criancas.end());

    for(auto &cr: criancas){
        cout << cr << "\n";
    }

    cout << "Se comportaram: " << c << " | Nao se comportaram: " << nc << "\n";

    return 0;
}